read -p "QED> " P;python3 -c 'import hashlib,json,sys;B="ATGC";X=sys.argv[1];R=[];N=21;exec("for n in range(N):\n D=\"\".join(B[(b>>s)&3]for b in X.encode()for s in(6,4,2,0));O=hashlib.sha256(D.encode()).hexdigest();S=hashlib.sha256((O+X).encode()).hexdigest();score=len(set(D))/4+int(O[0],16)/16+int(S[0],16)/16;R.append({\"n\":n,\"Omega\":O[:16],\"next\":S[:16],\"score\":round(score,4)});X=S");best=max(R,key=lambda x:x["score"]);print(json.dumps({"kernel":"QED.sh","principle":"analytic continuation + fixed point optimization","iterations":N,"best":best,"final_seed":X[:16],"status":"optimal candidate; not mathematical proof"},separators=(",",":")))' "$P"